content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, is that okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "請給我一杯冰的紅茶，半糖，可以嗎？",
      "pinyin": "Qǐng gěi wǒ yī bēi bīng de hóng chá, bàn táng, kěyǐ ma?",
      "pinyin_numeric": "qing3 gei3 wo3 yi1 bei1 bing1 de5 hong2 cha2, ban4 tang2, ke3 yi3 ma0?",
      "translation_en": "Please give me an iced black tea, half sugar, is that okay?",
      "translation_ko": "얼음 홍차 한 잔에 반당으로 주세요, 괜찮을까요?"
    },
    {
      "text": "我想要一杯熱的綠茶，少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi rè de lǜ chá, shǎo bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 re4 de5 lü4 cha2, shao3 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like a hot green tea, less ice, is that okay?",
      "translation_ko": "뜨거운 녹차 한 잔에 얼음 적게 주세요, 괜찮을까요?"
    },
    {
      "text": "麻煩你，我要一杯豆漿，內用，可以嗎？",
      "pinyin": "Má fan nǐ, wǒ yào yī bēi dòu jiāng, nèi yòng, kěyǐ ma?",
      "pinyin_numeric": "ma2 fan5 ni3, wo3 yao4 yi1 bei1 dou4 jiang1, nei4 yong4, ke3 yi3 ma0?",
      "translation_en": "Excuse me, I want a cup of soy milk, for here, is that okay?",
      "translation_ko": "실례합니다, 두유 한 잔에 매장에서 먹을게요, 괜찮을까요?"
    },
    {
      "text": "不好意思，我想要一杯大杯的拿鐵，去冰，可以嗎？",
      "pinyin": "Bù hǎo yì si, wǒ xiǎng yào yī bēi dà bēi de ná tiě, qù bīng, kěyǐ ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, wo3 xiang3 yao4 yi1 bei1 da4 bei1 de5 na2 tie3, qu4 bing1, ke3 yi3 ma0?",
      "translation_en": "Excuse me, I would like a large latte, no ice, is that okay?",
      "translation_ko": "죄송합니다, 큰 라떼 한 잔에 얼음 없이 주세요, 괜찮을까요?"
    },
    {
      "text": "請幫我加珍珠，可以嗎？",
      "pinyin": "Qǐng bāng wǒ jiā zhēn zhū, kěyǐ ma?",
      "pinyin_numeric": "qing3 bang1 wo3 jia1 zhen1 zhu1, ke3 yi3 ma0?",
      "translation_en": "Please help me add boba, is that okay?",
      "translation_ko": "타피오카 펄을 추가해 주세요, 괜찮을까요?"
    },
    {
      "text": "我想要一杯中杯的紅茶，正常甜，外帶，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi de hóng chá, zhèng cháng tián, wài dài, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 de5 hong2 cha2, zheng4 chang2 tian2, wai4 dai4, ke3 yi3 ma0?",
      "translation_en": "I would like a medium black tea, normal sweetness, to go, is that okay?",
      "translation_ko": "중간 크기 홍차 한 잔에 일반 당도로 포장해 주세요, 괜찮을까요?"
    },
    {
      "text": "麻煩你，給我一個袋子，可以嗎？",
      "pinyin": "Má fan nǐ, gěi wǒ yī ge dài zi, kěyǐ ma?",
      "pinyin_numeric": "ma2 fan5 ni3, gei3 wo3 yi1 ge5 dai4 zi5, ke3 yi3 ma0?",
      "translation_en": "Excuse me, give me a bag, is that okay?",
      "translation_ko": "실례합니다, 봉투 하나 주세요, 괜찮을까요?"
    },
    {
      "text": "不好意思，我要一杯冰的拿鐵，微糖，可以嗎？",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi bīng de ná tiě, wēi táng, kěyǐ ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, wo3 yao4 yi1 bei1 bing1 de5 na2 tie3, wei1 tang2, ke3 yi3 ma0?",
      "translation_en": "Excuse me, I want an iced latte, low sugar, is that okay?",
      "translation_ko": "죄송합니다, 얼음 라떼 한 잔에 당도 적게 주세요, 괜찮을까요?"
    },
    {
      "text": "請幫我拿一根吸管，可以嗎？",
      "pinyin": "Qǐng bāng wǒ ná yī gēn xī guǎn, kěyǐ ma?",
      "pinyin_numeric": "qing3 bang1 wo3 na2 yi1 gen1 xi1 guan3, ke3 yi3 ma0?",
      "translation_en": "Please help me get a straw, is that okay?",
      "translation_ko": "빨대 하나를 가져다 주세요, 괜찮을까요?"
    }
  ]
}
